<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<title>Personal Expense Tracker</title>
<style>
  :root {
    --bg: #f4f6f8;
    --card: #ffffff;
    --border: #d7dde3;
    --accent: #2f6690;
    --danger: #c0392b;
    --text: #1f2933;
    --muted: #6b7684;
  }
  * { box-sizing: border-box; }
  body {
    font-family: system-ui, -apple-system, Segoe UI, Roboto, Arial, sans-serif;
    background: var(--bg);
    color: var(--text);
    margin: 0;
    padding: 24px;
  }
  h1 { font-size: 1.4rem; margin-bottom: 16px; }
  h2 { font-size: 1.05rem; margin: 0 0 10px; }
  .card {
    background: var(--card);
    border: 1px solid var(--border);
    border-radius: 8px;
    padding: 16px;
    margin-bottom: 16px;
    max-width: 720px;
  }
  form {
    display: flex;
    flex-wrap: wrap;
    gap: 10px;
    align-items: flex-end;
  }
  .field {
    display: flex;
    flex-direction: column;
    gap: 4px;
    font-size: 0.85rem;
    color: var(--muted);
  }
  input, select, button {
    font-size: 0.95rem;
    padding: 7px 9px;
    border: 1px solid var(--border);
    border-radius: 6px;
    background: #fff;
    color: var(--text);
  }
  #amount { width: 110px; }
  #note { width: 160px; }
  button {
    cursor: pointer;
    background: var(--accent);
    color: white;
    border: none;
    padding: 8px 14px;
  }
  button:hover { opacity: 0.92; }
  #form-error {
    color: var(--danger);
    font-size: 0.85rem;
    min-height: 1.1em;
    margin-top: 8px;
  }
  .filters {
    display: flex;
    flex-wrap: wrap;
    gap: 10px;
    align-items: flex-end;
  }
  table {
    width: 100%;
    border-collapse: collapse;
    margin-top: 8px;
  }
  th, td {
    text-align: left;
    padding: 8px 6px;
    border-bottom: 1px solid var(--border);
    font-size: 0.9rem;
  }
  th { color: var(--muted); font-weight: 600; }
  .exp-del {
    background: transparent;
    color: var(--danger);
    border: 1px solid var(--danger);
    padding: 3px 9px;
    font-size: 0.8rem;
  }
  .exp-del:hover { background: var(--danger); color: #fff; }
  .summary-line {
    display: flex;
    justify-content: space-between;
    font-weight: 600;
    margin-top: 10px;
    font-size: 1.05rem;
  }
  .cat-summary {
    display: flex;
    flex-wrap: wrap;
    gap: 10px;
    margin-top: 10px;
  }
  .cat-total {
    background: #eef2f6;
    border-radius: 6px;
    padding: 6px 10px;
    font-size: 0.85rem;
  }
  .empty-row td {
    color: var(--muted);
    font-style: italic;
    text-align: center;
  }
</style>
</head>
<body>

<h1>Personal Expense Tracker</h1>

<div class="card">
  <h2>Add Expense</h2>
  <form id="expense-form">
    <div class="field">
      <label for="amount">Amount</label>
      <input type="number" id="amount" step="0.01" placeholder="0.00">
    </div>
    <div class="field">
      <label for="category">Category</label>
      <select id="category">
        <option value="groceries">Groceries</option>
        <option value="transport">Transport</option>
        <option value="bills">Bills</option>
        <option value="fun">Fun</option>
      </select>
    </div>
    <div class="field">
      <label for="date">Date</label>
      <input type="date" id="date">
    </div>
    <div class="field">
      <label for="note">Note</label>
      <input type="text" id="note" placeholder="Optional">
    </div>
    <button type="submit" id="add-expense">Add Expense</button>
  </form>
  <div id="form-error"></div>
</div>

<div class="card">
  <h2>Filters</h2>
  <div class="filters">
    <div class="field">
      <label for="filter-category">Category</label>
      <select id="filter-category">
        <option value="all">All</option>
        <option value="groceries">Groceries</option>
        <option value="transport">Transport</option>
        <option value="bills">Bills</option>
        <option value="fun">Fun</option>
      </select>
    </div>
    <div class="field">
      <label for="filter-from">From</label>
      <input type="date" id="filter-from">
    </div>
    <div class="field">
      <label for="filter-to">To</label>
      <input type="date" id="filter-to">
    </div>
  </div>
</div>

<div class="card">
  <h2>Expenses</h2>
  <table>
    <thead>
      <tr><th>Amount</th><th>Category</th><th>Date</th><th>Note</th><th></th></tr>
    </thead>
    <tbody id="expense-list"></tbody>
  </table>
  <div class="summary-line">
    <span>Total</span>
    <span id="total">0.00</span>
  </div>
  <div class="cat-summary" id="cat-summary"></div>
</div>

<script>
(function () {
  var STORAGE_KEY = 'expenses.v1';
  var CATEGORIES = ['groceries', 'transport', 'bills', 'fun'];

  var form = document.getElementById('expense-form');
  var amountInput = document.getElementById('amount');
  var categoryInput = document.getElementById('category');
  var dateInput = document.getElementById('date');
  var noteInput = document.getElementById('note');
  var formError = document.getElementById('form-error');

  var filterCategory = document.getElementById('filter-category');
  var filterFrom = document.getElementById('filter-from');
  var filterTo = document.getElementById('filter-to');

  var expenseList = document.getElementById('expense-list');
  var totalEl = document.getElementById('total');
  var catSummaryEl = document.getElementById('cat-summary');

  var expenses = loadExpenses();

  function loadExpenses() {
    try {
      var raw = localStorage.getItem(STORAGE_KEY);
      var parsed = raw ? JSON.parse(raw) : [];
      return Array.isArray(parsed) ? parsed : [];
    } catch (e) {
      return [];
    }
  }

  function saveExpenses() {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(expenses));
  }

  function escapeHtml(str) {
    var div = document.createElement('div');
    div.textContent = str;
    return div.innerHTML;
  }

  function formatMoney(n) {
    return n.toFixed(2);
  }

  function buildCatSummaryElements() {
    catSummaryEl.innerHTML = '';
    CATEGORIES.forEach(function (cat) {
      var el = document.createElement('div');
      el.className = 'cat-total';
      el.setAttribute('data-cat', cat);
      el.textContent = cat + ': 0.00';
      catSummaryEl.appendChild(el);
    });
  }

  function passesFilters(exp) {
    var cat = filterCategory.value;
    if (cat !== 'all' && exp.category !== cat) return false;
    var from = filterFrom.value;
    var to = filterTo.value;
    if (from && exp.date < from) return false;
    if (to && exp.date > to) return false;
    return true;
  }

  function render() {
    expenseList.innerHTML = '';

    var sorted = expenses.slice().sort(function (a, b) {
      if (a.date !== b.date) return a.date < b.date ? 1 : -1;
      return b.id - a.id;
    });

    var visible = sorted.filter(passesFilters);

    if (visible.length === 0) {
      var emptyRow = document.createElement('tr');
      emptyRow.className = 'empty-row';
      emptyRow.innerHTML = '<td colspan="5">No expenses to show</td>';
      expenseList.appendChild(emptyRow);
    } else {
      visible.forEach(function (exp) {
        var row = document.createElement('tr');
        row.className = 'expense';
        row.setAttribute('data-id', exp.id);
        row.innerHTML =
          '<td>' + formatMoney(exp.amount) + '</td>' +
          '<td>' + escapeHtml(exp.category) + '</td>' +
          '<td>' + escapeHtml(exp.date) + '</td>' +
          '<td>' + escapeHtml(exp.note || '') + '</td>' +
          '<td><button class="exp-del" data-id="' + exp.id + '">Delete</button></td>';
        expenseList.appendChild(row);
      });
    }

    var total = 0;
    var catTotals = {};
    CATEGORIES.forEach(function (c) { catTotals[c] = 0; });

    visible.forEach(function (exp) {
      total += exp.amount;
      if (catTotals.hasOwnProperty(exp.category)) {
        catTotals[exp.category] += exp.amount;
      }
    });

    totalEl.textContent = formatMoney(total);

    CATEGORIES.forEach(function (cat) {
      var el = catSummaryEl.querySelector('.cat-total[data-cat="' + cat + '"]');
      if (el) {
        el.textContent = cat + ': ' + formatMoney(catTotals[cat]);
      }
    });
  }

  form.addEventListener('submit', function (e) {
    e.preventDefault();

    var rawAmount = amountInput.value;
    var amount = parseFloat(rawAmount);
    var category = categoryInput.value;
    var date = dateInput.value;
    var note = noteInput.value.trim();

    if (rawAmount === '' || isNaN(amount) || amount <= 0) {
      formError.textContent = 'Please enter a valid amount greater than zero.';
      return;
    }
    if (!date) {
      formError.textContent = 'Please choose a date.';
      return;
    }

    formError.textContent = '';

    var expense = {
      id: Date.now() + Math.floor(Math.random() * 1000),
      amount: amount,
      category: category,
      date: date,
      note: note
    };

    expenses.push(expense);
    saveExpenses();

    amountInput.value = '';

    render();
  });

  expenseList.addEventListener('click', function (e) {
    var target = e.target;
    if (target && target.classList.contains('exp-del')) {
      var id = Number(target.getAttribute('data-id'));
      expenses = expenses.filter(function (exp) { return exp.id !== id; });
      saveExpenses();
      render();
    }
  });

  filterCategory.addEventListener('change', render);
  filterFrom.addEventListener('change', render);
  filterTo.addEventListener('change', render);

  buildCatSummaryElements();
  render();
})();
</script>

</body>
</html>
